-- luacheck: no max line length
return {
  ["efd00d.example_advanced.f6f9d9"] = "Hi, Tab! I have {apples} apples with me! You can have {apples / 2} of them.",
  ["efd00d.example_advanced.bf0cb8"] = "Thanks!",
  ["efd00d.example_advanced.aaf810"] = "Something is happening",
  ["efd00d.example_advanced.09e9be"] = "Something is true",
  ["efd00d.example_advanced.a62223"] = "Something else is true",
  ["efd00d.example_advanced.18af5b"] = "Anything else is true",
  ["efd00d.example_advanced.2b0249"] = "Neither \"something\" nor \"something else\" nor \"anything else\" are true",
  ["efd00d.triggered_warning_authorities.b4a680"] = "Things are not looking good.",
  ["efd00d.triggered_warning_authorities.66d6dd"] = "Reports are coming in of procedural breaches. City hall's unhappy. That's you.",
  ["efd00d.triggered_warning_authorities.422aee"] = "Get your act together, or I'll be forced to take you off the team.",
  ["efd00d.triggered_warning_authorities.a6ad2a"] = "That is all.",
  ["efd00d.triggered_informer_intro.dc2157"] = "She wasn't easy to get, but I'd like you to meet the lovely Rachel Ezra.",
  ["efd00d.triggered_informer_intro.dd764d"] = "Hi.",
  ["efd00d.triggered_informer_intro.e94d51"] = "She has some relevant second-hand intel about the Front for us.",
  ["efd00d.triggered_informer_intro.bcc4ea"] = "I'll leave you to it.",
  ["efd00d.triggered_informer_intro.2969af"] = "This young lady is Rachel Ezra.",
  ["efd00d.triggered_informer_intro.22c9b7"] = "This is our new informer, Rachel Ezra.",
  ["efd00d.triggered_informer_intro.bf20c2"] = "This is Rachel Ezra, Detective.",
  ["efd00d.triggered_informer_intro.712a55"] = "Coffee? Water?",
  ["efd00d.triggered_informer_intro.e2d2bd"] = "No, I'm good. Let's just get this over quick, please.",
  ["efd00d.triggered_informer_intro.7b0eea"] = "Have a seat. Ready?",
  ["efd00d.triggered_informer_intro.c6df7b"] = "Mhm. What do you need to know?",
  ["efd00d.triggered_informer_intro.29d88f"] = "There's no need to be nervous.",
  ["efd00d.triggered_informer_intro.c66b79"] = "If you say so.",
  ["efd00d.triggered_torture_e1.3fd8a5"] = "Come in for a second.",
  ["efd00d.triggered_torture_e1.c8a00c"] = "I've been reviewing your interrogation tapes.",
  ["efd00d.triggered_torture_e1.4b4206"] = "Care to explain why there are gaps on them?",
  ["efd00d.triggered_torture_e1.a271f1"] = "Oh. I thought it'd be best not to record hurting the suspects.",
  ["efd00d.triggered_torture_e1.940b4e"] = "...I'll just assume that was sarcasm.",
  ["efd00d.triggered_torture_e1.ff3a56"] = "Oh, uhm. I had some technical problems.",
  ["efd00d.triggered_torture_e1.bd69be"] = "Well, that's not what Peterson is saying. He's telling people you hurt him.",
  ["efd00d.triggered_torture_e1.7ec640"] = "Well, that's not what Cox is saying. He's telling people you hurt him.",
  ["efd00d.triggered_torture_e1.5fe75b"] = "Well, that's not what they're saying. They're telling people you hurt them.",
  ["efd00d.triggered_torture_e1.bf4aa2"] = "I have no idea why there'd be any gaps.",
  ["efd00d.triggered_torture_e1.9f3801"] = "Well, in the future, make sure that recorder is working throughout.",
  ["efd00d.triggered_torture_e1.42ff10"] = "Any accusations they make about being hurt become more credible when there are gaps in the recording.",
  ["efd00d.triggered_torture_e1.8a35a1"] = "Be dead careful about that.",
  ["efd00d.triggered_torture_e1.dd837a"] = "That's all.",
  ["efd00d.triggered_community_outreach.28f48a"] = "Mayor Patel wanted me to congratulate you on the community outreach your department has been doing.",
  ["efd00d.triggered_community_outreach.1030f8"] = "It's initiatives like yours that give the police department and all of us a good name.",
  ["efd00d.triggered_community_outreach.b0fe2d"] = "Be sure to drop a hint of what we do to the press, when you have the opportunity. Consider us even.",
  ["efd00d.triggered_community_outreach.0dfae1"] = "Well, I don't do it for you, I do it because we need to encourage more good cops to take up the fight.",
  ["efd00d.triggered_community_outreach.9922e1"] = "There's no better expression of gratitude than a budget boost, my friend.",
  ["efd00d.triggered_community_outreach.112550"] = "We'll see how we can help then.",
  ["efd00d.triggered_assassinated.8fd561"] = "Well, I'm headed home.",
  ["efd00d.triggered_assassinated.80f972"] = "Jen, should I drop you off someplace?",
  ["efd00d.triggered_assassinated.cd2190"] = "Nah, I'll wait for Tab to come out. Maybe sneak a cig'.",
  ["efd00d.triggered_assassinated.de3bd4"] = "Okay, well, 'night boss, Jen'.",
  ["efd00d.triggered_assassinated.90fdfe"] = "'Night, Morty.",
  ["efd00d.triggered_assassinated.1b3db5"] = "Good night, Fischer.",
  ["efd00d.triggered_assassinated.53707b"] = "See you first thing tomorrow. Rest well.",
  ["efd00d.triggered_assassinated.e15c42"] = "G'night Mort.",
  ["efd00d.triggered_assassinated.d1db17"] = "You want a cigarette too, b-",
  ["efd00d.triggered_assassinated.efe573"] = "Huh.",
  ["efd00d.triggered_assassinated.2b07b4"] = "Erm, I think that person behind you migh-",
  ["efd00d.triggered_fired.6c18b8"] = "Enough is enough.",
  ["efd00d.triggered_fired.7583b1"] = "I can't keep you on the job with the way you're performing.",
  ["efd00d.triggered_fired.5c87fd"] = "You're off the Liberation Front.",
  ["efd00d.triggered_fired.94be6d"] = "And suspended indefinitely pending further internal investigation into your actions and overall competence.",
  ["efd00d.triggered_fired.d076b9"] = "Leave your badge, gun - and get out.",
  ["efd00d.triggered_torture1.2f2dd8"] = "Hey boss, wanted to talk about the interview tapes real quick.",
  ["efd00d.triggered_torture1.7fc393"] = "There's a gap on one of'm. And at least one of the subject is not only telling their lawyer but also the media that you roughed them up during that pause. They might even press charges.",
  ["efd00d.triggered_torture1.b506ae"] = "Look, you're running the show here. I just want you to stay aware that, even if it's their word against yours, there could be consequences if this keeps on repeating.",
  ["efd00d.triggered_torture1.75c1fc"] = "Authorities might be pressured to fire you. People might start targetting you as a bad guy. We have to be smart, remain the good guys.",
  ["efd00d.triggered_torture1.d91eec"] = "That'll be quite enough, Jennifer. I don't need a lecture, I need you to do good police work.",
  ["efd00d.triggered_torture1.940181"] = "Right... Will, uh - will do.",
  ["efd00d.triggered_torture1.f0427e"] = "Jennifer, look, I'm going to be doing my absolute best to save people. If that means my job or looking bad, so be it.",
  ["efd00d.triggered_torture1.d770c2"] = "Understood. I'll get back to work.",
  ["efd00d.triggered_torture1.9b0e62"] = "You're right. I need to be careful about these things. There's no point to any of this if we become the bad guys.",
  ["efd00d.triggered_torture1.e33f68"] = "Glad to hear it, boss. I'll get back to work.",
  ["efd00d.triggered_torture2.04c50e"] = "Can we speak, Detective?",
  ["efd00d.triggered_torture2.b0a8b6"] = "We are having repeat occurences of gaps on the interview tapes.",
  ["efd00d.triggered_torture2.6fc214"] = "I've checked the devices and the problems aren't technical.",
  ["efd00d.triggered_torture2.6c2b36"] = "I won't report this myself... in the interest of team cohesion.",
  ["efd00d.triggered_torture2.26138b"] = "But if this persists, the consequences upon this department will come from outside, and will be harsh.",
  ["efd00d.triggered_torture2.cd7b45"] = "Noted, Thompson. Back to work.",
  ["efd00d.triggered_torture2.132544"] = "I see. Very well.",
  ["efd00d.triggered_torture2.b4204f"] = "You're right, Tab, but I have to balance procedure and getting results.",
  ["efd00d.triggered_torture2.490429"] = "Compromising procedure is already showing a failure to balance. I'll leave you to it.",
  ["efd00d.triggered_torture2.da34fa"] = "It's so hard to get answers otherwise. But you're right. I'll make sure to always leave it on - it's a promise.",
  ["efd00d.triggered_torture2.858f8c"] = "I think that would be best.",
  ["efd00d.triggered_warning_popularity.b4a680"] = "Things are not looking good.",
  ["efd00d.triggered_warning_popularity.dd2f07"] = "We're receiving actual complaints from the general public about your leadership of the unit.",
  ["efd00d.triggered_warning_popularity.c49e49"] = "Get your act together! Spurred on by the Front, who knows what these people might end up doing.",
  ["efd00d.triggered_warning_popularity.a6ad2a"] = "That is all.",
  ["efd00d.triggered_recruited_joseph.ec5a51"] = "Team, I'd like you to meet Mr. Ward, here to help us despite his retirement.",
  ["efd00d.triggered_recruited_joseph.7c7944"] = "Please, call me Joseph, or Joe.",
  ["efd00d.triggered_recruited_joseph.30efcf"] = "Team, please meet Joseph. He's an old-school terrorist-squasher, here to aid us in crushing the Front.",
  ["efd00d.triggered_recruited_joseph.20de82"] = "Joseph Ward, this is the team. Team, this is Joseph. He'll be joining us to improve our field work.",
  ["efd00d.triggered_recruited_joseph.d32509"] = "Welcome, Joseph.",
  ["efd00d.triggered_recruited_joseph.bcbc6f"] = "It's great to have some reinforcements.",
  ["efd00d.triggered_recruited_joseph.55e80b"] = "Your resume is quite impressive; your contributions may be invaluable.",
  ["efd00d.triggered_recruited_joseph.d6e517"] = "Thank you kindly for having me. It's daunting, yet thrilling, to be back.",
  ["efd00d.triggered_joseph_intro.c142ac"] = "Chief, someone's here to see you.",
  ["efd00d.triggered_joseph_intro.3d2610"] = "This is Joseph Ward. More than two decades ago, he led a team sorta' like ours against the Burgundy Riots.",
  ["efd00d.triggered_joseph_intro.99c894"] = "Greetings.",
  ["efd00d.triggered_joseph_intro.1a39f7"] = "Meeting room's ready for you.",
  ["efd00d.triggered_professor_intro.450bda"] = "Doctor Olaru, from the University, is here to speak to you. She is in the meeting room already.",
  ["efd00d.triggered_professor_intro.ce7491"] = "Seems quite lovely!",
  ["efd00d.triggered_professor_intro.05ec93"] = "She should be able to shed some light on the Front's motives.",
  ["efd00d.triggered_professor_intro.34db4a"] = "Brought that hot little number, Doctor Olaru, to the meeting room for you.",
  ["efd00d.triggered_professor_intro.51e148"] = "Extract that quality University insight from her, and we can use it against the Front.",
  ["efd00d.triggered_professor_intro.40617f"] = "And maybe after, I can extract a phone number...",
  ["efd00d.triggered_professor_intro.0c392a"] = "Doctor Olaru's in the meeting room for you.",
  ["efd00d.triggered_professor_intro.ba6adb"] = "Maybe she can give us the lowdown on how the Front actually thinks.",
  ["efd00d.triggered_professor_intro.8f05f6"] = "Professor Olaru is waiting in the meeting room to speak to you.",
  ["efd00d.triggered_professor_intro.bc1f1d"] = "She has rich insight into the ideology of such groups.",
  ["efd00d.triggered_professor_intro.a1ceea"] = "She can surely enlighten us about the Liberation Front's essence.",
  ["efd00d.triggered_civil_forfeiture.11834c"] = "This constant sending of agents to look for civil forfeiture opportunities is looking suspicious, detective.",
  ["efd00d.triggered_civil_forfeiture.1b932d"] = "It'll look terrible if the public or press catches wind of it, and frames it as an asset grab.",
  ["efd00d.triggered_civil_forfeiture.2e858f"] = "Not to mention some of the assets seized were lifted from friends of the mayor.",
  ["efd00d.triggered_civil_forfeiture.8eb5e0"] = "Well, combating terrorists requires resources. Tell the press that.",
  ["efd00d.triggered_civil_forfeiture.2887b6"] = "That's the system, that's the law. I can confiscate those assets. The rest is your problem.",
  ["efd00d.triggered_civil_forfeiture.f4ae9e"] = "Fine, I'll try and be more careful by doing civil forfeitures from poorer neighbourhoods - this way, I won't hit important people.",
  ["efd00d.triggered_fred_intro.546670"] = "Ah, this good ol' refreshing evening air is nice.",
  ["efd00d.triggered_fred_intro.8a19d6"] = "Say, boss, are you sure we did right here by getting Ennis a transfer?",
  ["efd00d.triggered_fred_intro.e8de6e"] = "He might have usable intel. If he doesn't, it will have been a mistake.",
  ["efd00d.triggered_fred_intro.ef4fa2"] = "Fair enough.",
  ["efd00d.triggered_fred_intro.bc6610"] = "I guess even the smallest nuggets of info from a low-level guy like him could still be valuable.",
  ["efd00d.triggered_fred_intro.adbed5"] = "Even if he doesn't have usable intel, we at least helped him escape Drasko's bullying.",
  ["efd00d.triggered_fred_intro.b76d42"] = "Dunno' why the asshole deserves any saving.",
  ["efd00d.triggered_fred_intro.dc7412"] = "Oh, I made sure he gets transferred into a much worse prison. It has the lowest survival rate for its security level in the state. But he'll only know that after our little talk.",
  ["efd00d.triggered_fred_intro.d555f9"] = "Oh wow. No pity for the guy, but...",
  ["efd00d.triggered_fred_intro.091e63"] = "That's pretty brutal stuff.",
  ["efd00d.triggered_fred_intro.73c758"] = "Well, time to go talk to him. Let's get in the car.",
  ["efd00d.triggered_fred_intro.df4e66"] = "I'll drive.",
  ["7f031e.interview1.1b4964"] = "We've got a reporter in. I'm gonna' ask you to try and answer a few of his questions.",
  ["7f031e.interview1.b157e8"] = "This is Eddie Walker, from the Heraldic.",
  ["7f031e.interview1.d483c6"] = "Greetings, officer.",
  ["7f031e.interview1.a73403"] = "Are you ready to get started?",
  ["7f031e.interview1.bcc4ea"] = "I'll leave you to it.",
  ["7f031e.interview1.4411b2"] = "Let's make this snappy.",
  ["7f031e.interview1.dc66e1"] = "Let me get my files first - in case I need to give details.",
  ["7f031e.interview1.586730"] = "Let me clear the room first - make sure we have some privacy.",
  ["7f031e.interlude_c1_cptutorial.b0b54a"] = "As part of leading your team, you'll have to manage budget and assign missions.",
  ["7f031e.interlude_c1_cptutorial.a0585c"] = "For budgeting, you'll be getting $3000 with each budget round.",
  ["7f031e.interlude_c1_cptutorial.67419d"] = "For budgeting, you'll be getting $2000 with each budget round.",
  ["7f031e.interlude_c1_cptutorial.229927"] = "You can influence your available funds in many ways, and any sums unspent are saved for the next budget round.",
  ["7f031e.interlude_c1_cptutorial.abed33"] = "You can assign available agents to missions, on top of their core investigation work for the team.",
  ["7f031e.interlude_c1_cptutorial.62c653"] = "How well they'll do is determined by how motivated they are, and how much the task fits their background and expertise.",
  ["7f031e.interlude_c1_cptutorial.04b4bd"] = "I've ordered you an outsourced HR report - it's on me. It should tell you how well the agents might do on missions.",
  ["7f031e.interlude_c1_cptutorial.765a1c"] = "If you don't buy yourself expanded HR reports in the future, you won't know what their likelihood of success will be.",
  ["7f031e.interlude_c1_cptutorial.c4a2be"] = "Maintaining all facets of the image of your team is key. You need approval, or else you'll lose the team.",
  ["7f031e.interlude_c1_cptutorial.bfb4d8"] = "Buying expanded PR reports can help you understand what's causing shifts in your image.",
  ["7f031e.interlude_c1_cptutorial.9fa71c"] = "All set?",
  ["7f031e.interlude_c1_cptutorial.9fa6fe"] = "All set!",
  ["7f031e.interlude_c1_cptutorial.3d9f4d"] = "That sounds like a lot. How do I know what the consequences of each choice will be before I make them?",
  ["7f031e.interlude_c1_cptutorial.a0cf2d"] = "Uhm. Well, you don't.",
  ["7f031e.interlude_c1_cptutorial.418661"] = "It's your job to evaluate what the consequences and risks of each action and option might be.",
  ["7f031e.interlude_c1_cptutorial.a98798"] = "Use your reason, use trial-and-error.",
  ["7f031e.interlude_c1_cptutorial.c78129"] = "But this isn't the Police Academy, things are not transparent and don't have fixed and easily predictable effects.",
  ["7f031e.interlude_c1_cptutorial.73070a"] = "You think I had any idea hitting on that redhead back in college would mean I now have to go to marriage counselling?",
  ["7f031e.interlude_c1_cptutorial.0a4ed6"] = "I had no idea. That's what real life's like.",
  ["7f031e.interlude_c1_cptutorial.b73b1a"] = "Good luck.",
  ["7f031e.interlude_c2_1_jen.efb8fa"] = "So, hey - boss.",
  ["7f031e.interlude_c2_1_jen.800bd8"] = "Wanted to clear the water about some stuff that I don't know whether you're even aware of or not.",
  ["7f031e.interlude_c2_1_jen.4ebe40"] = "Chief Lucas was looking at the two of us to see who should head up this task force.",
  ["7f031e.interlude_c2_1_jen.288f6a"] = "I guess you aceing that Peterson grill made it a done deal, and I can't say I blame the Chief for that call.",
  ["7f031e.interlude_c2_1_jen.42f16e"] = "Bullshit rumors fly really easily, so just wanted to reassure you that I'm fully on board - right behind you.",
  ["7f031e.interlude_c2_1_jen.2a2e8b"] = "After all, the best leaders are also the best followers.",
  ["7f031e.interlude_c2_1_jen.dc051a"] = "If I had any idea, I would have told the Chief to give it to you. This responsibility feels like a lot.",
  ["7f031e.interlude_c2_1_jen.968acf"] = "Huh. Well, this is the situation we're in. We should make the best of it.",
  ["7f031e.interlude_c2_1_jen.cbb60c"] = "Thank you for the reassurance, Reyes. Step up your game and you'll lead your own unit in no time.",
  ["7f031e.interlude_c2_1_jen.ced2a6"] = "Erm, right.",
  ["7f031e.interlude_c2_1_jen.720377"] = "Glad to hear it, Jen. Let's do good work, whoever's managing this.",
  ["7f031e.interlude_c2_1_jen.31742f"] = "10-4, boss. 10-4.",
  ["7f031e.interlude_c2_1_jen.db7d1a"] = "Be one of the good guys. I'm here for the whole ride, heart and soul.",
  ["7f031e.interlude_c2_1_jen.93931c"] = "But if you're going to be an aggro bully-cop or bully-boss, I'm telling you plain and simple:",
  ["7f031e.interlude_c2_1_jen.09897e"] = "I will try my ethical best to replace you.",
  ["7f031e.interlude_c2_1_jen.382f30"] = "Get back in line Reyes. You're here to do police work, not bust my chops and make threats.",
  ["7f031e.interlude_c2_1_jen.55eed2"] = "The best police work I can do includes keeping an eye on you.",
  ["7f031e.interlude_c2_1_jen.6fc667"] = "Too much is at stake for me to look the other way.",
  ["7f031e.interlude_c2_1_jen.afdf27"] = "Well, that's unnecessarily confrontational, now isn't it? I'm really trying my best here.",
  ["7f031e.interlude_c2_1_jen.b4f06a"] = "Well, better make sure your best is good enough, then.",
  ["7f031e.interlude_c2_1_jen.f48fa2"] = "It's nothing personal, but all of this we have to deal with is much bigger than us.",
  ["7f031e.interlude_c2_1_jen.a98492"] = "Too much is at stake.",
  ["7f031e.interlude_c2_1_jen.9222b1"] = "Well look at Officer Uppity! Channeled agression has carried decades of police work, don't knock it.",
  ["7f031e.interlude_c2_1_jen.8739ca"] = "Oh puh-lease. Step into the new century whenever you're ready.",
  ["7f031e.interlude_c2_1_jen.c68478"] = "Too much is at stake for you to treat this operation as some sort of ego-trip.",
  ["7f031e.interlude_c2_1_jen.c99545"] = "My door's always open.",
  ["7f031e.interlude_c2_1_jen.03859d"] = "Good to know, mhm.",
  ["7f031e.interlude_c2_1_jen.53a6d3"] = "I'll be at my desk.",
  ["7f031e.interlude_c2_1_jen.c4cc96"] = "I've read your file, Jennifer. On Martha Hughes?",
  ["7f031e.interlude_c2_1_jen.b61ec9"] = "Oh? I wasn't aware you had access to that...",
  ["7f031e.interlude_c2_1_jen.ea45c5"] = "What about it?",
  ["7f031e.interlude_c2_1_jen.84f705"] = "Oh, I just wanted you to know that I know.",
  ["7f031e.interlude_c2_1_jen.77429c"] = "Yes, your power has been asserted. Great job.",
  ["7f031e.interlude_c2_1_jen.6ae0ae"] = "Just wanted to say you did the right thing there.",
  ["7f031e.interlude_c2_1_jen.230085"] = "I just did an evaluation, as per my expertise.",
  ["7f031e.interlude_c2_1_jen.5ded38"] = "But message received - and valued.",
  ["7f031e.interlude_c2_1_jen.4802b3"] = "I'd appreciate it if the matter stayed as classified as it's supposed to be.",
  ["7f031e.interlude_c2_1_jen.807300"] = "You let a murderer go free. I won't have that on this team. Understood?",
  ["7f031e.interlude_c2_1_jen.9ada95"] = "But message received.",
  ["7f031e.interlude_c2_1_jen.58e025"] = "Don't let the door hit you on the way out.",
  ["7f031e.interlude_c2_1_jen.d96ec2"] = "So mature.",
  ["7f031e.interlude_c2.3a492c"] = "I've been at it for a while now, and I've managed to figure out what most keywords mean.",
  ["7f031e.interlude_c2.7c83fb"] = "The algorithm managed to confirm some of these deductions. There are some conflicts though, either because of cognitive biases or of algorithm errors.",
  ["7f031e.interlude_c2.ffaf3f"] = "It's hard to figure out specifics, but we have some broad findings.",
  ["7f031e.interlude_c2.9e8e68"] = "The folks in the chat room are just a wing of the whole operation, though.",
  ["7f031e.interlude_c2.4ae9e3"] = "And I think I've stumbled onto something big. The Southbank Mall, sometime today, the planting of \"a package\".",
  ["7f031e.interlude_c2.7be262"] = "In front of the Duathlon store. Apparently they'll have someone there. I'm not sure what they're supposed to do, though.",
  ["7f031e.interlude_c2.7566ad"] = "We should have the place canvased ASAP. Let's move.",
  ["7f031e.interlude_c3.f7e4be"] = "We have a high probability track. We've decoded probable meanings for many of their terms - enough to understand basic plans.",
  ["7f031e.interlude_c3.5c27b9"] = "We're dealing with a cell. They're isolated from other cells.",
  ["7f031e.interlude_c3.91e74b"] = "And there seems to be something happening today. With over 80% probability - a threat inside the Southbank Mall.",
  ["7f031e.interlude_c3.6fbcc0"] = "An unknown agent, coded \"Patsy\", will be on the lookout in front of the Duathlon store, guarding some objective. Possibly explosive.",
  ["7f031e.interlude_c3.90138e"] = "Shit.",
  ["7f031e.interlude_c3.8549d5"] = "Let's get to the cars - we need to canvas that place!",
  ["7f031e.interlude_b3.ebc0e3"] = "We've got some live action, boss.",
  ["7f031e.interlude_b3.5ef68e"] = "Morty's out there with some badges grabbing our three suspects for who that \"Hornbunny\" might be.",
  ["7f031e.interlude_b3.851978"] = "I do hope Mr. Fischer practices restraint. I know him to be rather abrasive when bringing in people.",
  ["7f031e.interlude_b3.67bca9"] = "I'm sure Morty means well.",
  ["7f031e.interlude_b3.562b30"] = "Well, the terrorist among them deserves to be... abrased.",
  ["7f031e.interlude_b3.7305cb"] = "Procedure's important. Innocent until proven guilty.",
  ["7f031e.interlude_b3.755eba"] = "I'm going to get the rooms ready.",
  ["7f031e.interlude_b3.93a794"] = "There's an update being pushed to the chat room's software...",
  ["7f031e.interlude_b3.5408d4"] = "Darn. It seems that the Liberation Front have found out about our move. They've triggered the reallocation of passwords for the chat room.",
  ["7f031e.interlude_b3.2d8bb8"] = "It's just a matter of minutes before the current password becomes useless. We need to acquire a new one asap.",
  ["7f031e.interlude_b3.a84d72"] = "They're here. Get ready to interrogate'm.",
  ["7f031e.interlude_b3.37f066"] = "We'll line up the files.",
  ["7f031e.interlude_b2.58ef91"] = "Congratulations on your new assignment, Detective.",
  ["7f031e.interlude_b2.eec533"] = "Let me introduce some of the people you'll be working with.",
  ["7f031e.interlude_b2.e48e38"] = "This is Tab Thompson, analyst extraordinaire.",
  ["7f031e.interlude_b2.9ceb33"] = "I look forward to addressing the threat of the Liberation Front with you, Detective.",
  ["7f031e.interlude_b2.320c7f"] = "And this is Jennifer Reyes, Organized Crime department's best.",
  ["7f031e.interlude_b2.6906ad"] = "Delighted, Detective",
  ["7f031e.interlude_b2.2a18b2"] = "Mordecai Fischer, who we pulled from Homicide, will also be helping you out in the field.",
  ["7f031e.interlude_b2.bcc4ea"] = "I'll leave you to it.",
  ["7f031e.interlude_b2.f40693"] = "Shall we head out and talk some shop over at Hanningan's?",
  ["7f031e.interlude_b2.bfd5fe"] = "The meeting room is not being used...",
  ["7f031e.interlude_b2.8596ed"] = "Hannigan's sounds great.",
  ["7f031e.interlude_b2.14cf3f"] = "Let's take the meeting room.",
  ["7f031e.interlude_b2.10ac7b"] = "Let's just go straight to our desks. Chief already assigned us tasks to cover.",
  ["7f031e.interlude_c4.1ed828"] = "We have three suspects in custody. One of them can potentially be our perp.",
  ["7f031e.interlude_c4.bec8d6"] = "The only three we noticed to linger near the Duathlon store.",
  ["7f031e.interlude_c4.c07c71"] = "That is, before the three of them got tangled up in an incident, and we had to intervene.",
  ["7f031e.interlude_c4.e93cf5"] = "This is detailed in the file I drafted up on the way here.",
  ["7f031e.interlude_c4.14a5e7"] = "One of them is the one working on the Liberation Front's orders. Has to be!",
  ["7f031e.interlude_c4.198ae1"] = "New hits of the algorithm indicate over a 90% chance that we're dealing with an IED planted in the mall.",
  ["7f031e.interlude_c4.ef52a4"] = "I've checked the chat room again. I now think we're dealing with a planted bomb.",
  ["7f031e.interlude_c4.df53ad"] = "Sweet baby Jesus... We're on the clock, boss.",
  ["7f031e.interlude_c4.3a5001"] = "Lives are at stake. We need the explosive device's location.",
  ["7f031e.interlude_b0.4b9359"] = "Good work in there. I have something important I need to discuss with you.",
  ["7f031e.interlude_b0.76e4af"] = "But before that, I need you to finish up the press release we're putting out about this case. Help them word it.",
  ["7f031e.interlude_b0.100ff0"] = "Then come see me.",
  ["7f031e.interlude_b1.3bfb9a"] = "This Liberation Front business you got out of Peterson, it seems to be pretty serious stuff.",
  ["7f031e.interlude_b1.ef2b78"] = "They've been claiming more and more hits, and seem to be behind things like assaults on politicians.",
  ["7f031e.interlude_b1.e9d754"] = "They appear to be expanding their operation, chiefly in our city.",
  ["7f031e.interlude_b1.439757"] = "So, I've talked it over with the powers that be, and we've decided you're the best person for the job.",
  ["7f031e.interlude_b1.5cd140"] = "You'll be heading up a small unit to combat these guys.",
  ["7f031e.interlude_b1.13131c"] = "We are pulling some of the best people from other departments to work with you.",
  ["7f031e.interlude_b1.0ac988"] = "Not gonna' lie - this unit'll mean all eyes will be on you. Try and keep everyone happy.",
  ["7f031e.interlude_b1.16210a"] = "But most importantly: stop these bastards.",
  ["7f031e.interlude_b1.f610c2"] = "Rest up. See you tomorrow.",
  ["7f031e.interlude_a.ca7085"] = "Hey - I need you to come in on a case.",
  ["7f031e.interlude_a.1eafd5"] = "Fischer's brought in a set of guys. They are in the interrogation rooms.",
  ["7f031e.interlude_a.1ff192"] = "Hey.",
  ["7f031e.interlude_a.7552d9"] = "We have the vic's husband - the only witness - and the robber that broke in.",
  ["7f031e.interlude_a.4e5a42"] = "We need your questioning magic in there - a confession - because all we have is circumstantial. You in?",
  ["7f031e.interlude_a.00fecb"] = "Sure thing.",
  ["7f031e.interlude_a.1a278d"] = "Yes, sir.",
  ["7f031e.interlude_a.c8dee2"] = "Ughhhh. Fine, fine...",
  ["7f031e.interlude_a.f0fa23"] = "So the story is this Cox broke in armed with a low cal piece, holding this Peterson up and tying him to a chair.",
  ["7f031e.interlude_a.b9af6b"] = "Wife comes in, jumps for the phone, Cox drops her with two shots to the back before bolting.",
  ["7f031e.interlude_a.4765e6"] = "We have the gun. No prints.",
  ["7f031e.interlude_a.53ae6a"] = "This Peterson was as cool as a cucumber: his wife's body just lying there in the other room.",
  ["7f031e.interlude_a.00e629"] = "Managed to track down and also grab Cox. Street contacts helped.",
  ["7f031e.interlude_a.74b600"] = "But we still don't have a clear picture of the murder.",
  ["7f031e.interlude_a.079a87"] = "Check out the files, grill them cross-examination, get me a confession. You have this.",
  ["7f031e.interlude_c.24c1c1"] = "Great job in there, boss!",
  ["7f031e.interlude_c.90159e"] = "Now that we were logged in, even for a second, we can analyze what they've been talking. At a first glance they seem to be using code-words.",
  ["7f031e.interlude_c.5a17cf"] = "I can set up a smart algorithm that can detect possible meanings from the contextual usage of words.",
  ["7f031e.interlude_c.31942b"] = "Or... we could simply try to figure it out directly.",
  ["7f031e.interlude_c.5394a8"] = "I don't trust algorithms. Jennifer, look at their conversations and try to figure out what they've been talking about.",
  ["7f031e.interlude_c.63fe9d"] = "Codes may be deceiving to the naked eye. Let the algorithms do the work. Tell me what pops up.",
  ["7f031e.interlude_c.3b430c"] = "Do both. Set up the algorithms and also try to figure things out manually.",
  ["7f031e.interlude_c.7ee20f"] = "This will mean that both of us will be busy working on this. We may have a hard time responding to other issues that pop up.",
  ["7f031e.interlude_c.ee535c"] = "Do both anyway. We'll see what bites.",
  ["7f031e.interlude_c.8ed40f"] = "Fine, forget the algorithms then. Intuition will be our weapon.",
  ["7f031e.interlude_c.33c63d"] = "Okay, let the computer do the work then.",
  ["80035d.interlude_e2.a3ff9d"] = "Countless hours of grilling Adams, and I have nothing.",
  ["80035d.interlude_e2.a3cebf"] = "Well, I bring good news.",
  ["80035d.interlude_e2.f85a68"] = "It was a long questioning, but I've managed to gather an extensive list of descriptions and partial names from Nowak.",
  ["80035d.interlude_e2.0fbf7c"] = "Each is a potential hit or a dud. We have to start digging into this list.",
  ["80035d.interlude_e2.0d3af2"] = "There is a full name here. Helene Koufos. I'll see if I can track her down.",
  ["80035d.hannigan2_intro.630f78"] = "If I may briefly interrupt you with a social matter?",
  ["80035d.hannigan2_intro.c94fc7"] = "The team is partaking in socialising at Hannigan's tonight.",
  ["80035d.hannigan2_intro.b32213"] = "Would you like to join us?",
  ["80035d.hannigan2_intro.ed9a18"] = "No can do, sorry. I have to go to this media training thing. It's all about how you talk to the press. Have fun.",
  ["80035d.hannigan2_intro.402410"] = "Sure, I'll see you all there.",
  ["80035d.hannigan2.19e868"] = "...mayor Patel's just way too hot. She has to be the Kiss!",
  ["80035d.hannigan2.94a600"] = "I'm confident in picking her for Marry.",
  ["80035d.hannigan2.93d69c"] = "So, you're killing Damascus Reed? Seems like a waste of the many millions in his accounts?",
  ["80035d.hannigan2.408b57"] = "So, you're killing Damascus Reed? Why not Marry instead into all that start-up millionaire money?",
  ["80035d.hannigan2.57c661"] = "Oh, I'm sure. He remains in the Kill category.",
  ["80035d.hannigan2.9f7740"] = "Boss, your go. And since we're doing people in high places...",
  ["80035d.hannigan2.0ddbd7"] = "Kiss, Marry, Kill. Chief Anderson, Patricia Becker with the Heraldic -",
  ["80035d.hannigan2.75a884"] = "Nice!",
  ["80035d.hannigan2.73d3ac"] = "- and Tristan, that guy from City Hall!",
  ["80035d.hannigan2.d92fbc"] = "Who's it going to be?",
  ["80035d.hannigan2.885a89"] = "Who's it gonna' be?",
  ["80035d.hannigan2.78412f"] = "Hmm, I'll be kissing Chief Anderson. Aggressively.",
  ["80035d.hannigan2.d8b1c7"] = "I have to kiss Patricia Becker. She's a fit lady.",
  ["80035d.hannigan2.7aaa67"] = "Kissing Tristan. He's a fit gentleman.",
  ["80035d.hannigan2.0cb20c"] = "I'll marry Chief Anderson Seems like he'd be a good dad.",
  ["80035d.hannigan2.c7eea9"] = "I'll marry Patricia Becker. Maybe improve our press coverage.",
  ["80035d.hannigan2.1f0404"] = "Marry Tristan. That boy has a bright political future.",
  ["80035d.hannigan2.6a4cef"] = "...And unfortunately kill the Chief. By elimination of the other options.",
  ["80035d.hannigan2.4dc675"] = "...And unfortunately kill miss Becker. By elimination of the other options.",
  ["80035d.hannigan2.f88772"] = "...And unfortunately kill Tristan. By elimination of the other options.",
  ["80035d.hannigan2.3039dd"] = "Oh, that bigger table has cleared. Let's move over!",
  ["80035d.interlude_e3.0634c3"] = "Koufos is extremely shady.",
  ["80035d.interlude_e3.286241"] = "She had been asking plenty of questions about the final bomb site, both online and offline.",
  ["80035d.interlude_e3.97c2f5"] = "Even visits to the site for thinly-veiled reasons.",
  ["80035d.interlude_e3.0f71b4"] = "Clients of her yoga studio reported that she tried to interest them in an organization which wanted \"to make a new world\".",
  ["80035d.interlude_e3.358465"] = "We have a strong suspicion about who she might be on the chatroom - even though it's gone quite quiet.",
  ["80035d.interlude_e3.f80e34"] = "So, I think we have a slam-dunk Liberation Front member in our grasp.",
  ["80035d.interlude_e3.80d76e"] = "Probably a false flag, but bring them in to check.",
  ["80035d.interlude_e3.1bf95e"] = "Ugh, finally! Bring them in!",
  ["80035d.interlude_e3.e2dc10"] = "Fuck yea! Interrogation time!",
  ["80035d.interlude_e3.8f7723"] = "Well, I've already sent a squad to bring her in. She seems absent from the regular locations for a few hours now.",
  ["80035d.interlude_e3.9b2715"] = "So, it might be a while. But I have other good news.",
  ["80035d.interlude_e3.72ccaf"] = "Koufos has had a lot of contact with one Cassandra Higgs.",
  ["80035d.interlude_e3.30bffc"] = "Meetings, money transfers, contact between the two spiked significantly before the attacks.",
  ["80035d.interlude_e3.08795b"] = "So, while we look for Koufos, I'll grab Morty and try to find Higgs.",
  ["80035d.interview2.944751"] = "Mayor Patel has kindly asked that you speak to another reporter, and Chief Anderson has signed off on it too.",
  ["80035d.interview2.a7073f"] = "This is Patricia Becker, perhaps the city's most respected journalist.",
  ["80035d.interview2.cf6365"] = "Good day, officer.",
  ["80035d.interview2.95b5d6"] = "Tristan, you're too kind.",
  ["80035d.interview2.d9d6dd"] = "And I just want to assure you, officer, that this interview will be fair and open.",
  ["80035d.interview2.8cf665"] = "No, fuck this. I'm not talking to the press. My department's actions speak for themselves.",
  ["80035d.interview2.60ca63"] = "Ughh, fine. Let's get this over with. Don't take too long - I have actual work to do.",
  ["80035d.interview2.3fa105"] = "I'd be happy to, Miss Becker. This way.",
  ["80035d.interlude_e1.bdf0fb"] = "Great job boss. Now that we have Adams and poor Nowak, we should get to grilling them.",
  ["80035d.interlude_e1.2747a7"] = "Which one of us you want on Nowak?",
  ["80035d.interlude_e1.5e665d"] = "Tab, you take Nowak.",
  ["80035d.interlude_e1.6cde4d"] = "Jennifer, you take Nowak.",
  ["80035d.interlude_e1.237a5d"] = "Morty, you take Nowak.",
  ["80035d.interlude_e1.b39bcd"] = "And on Gabriel Adams?",
  ["80035d.interlude_e1.1540b9"] = "Morty, you take Adams.",
  ["80035d.interlude_e1.5ea4a9"] = "Jennifer, you take Adams.",
  ["80035d.interlude_e1.502cb9"] = "Tab, you take Adams.",
  ["80035d.interlude_e1.bdc05e"] = "Adams won't give us anything. I want the rest of you ready for any mission, instead.",
  ["80035d.hannigan1_intro.ddb622"] = "Hey, boss?",
  ["80035d.hannigan1_intro.a3bc94"] = "I'm going to meet the others at Hannigan's.",
  ["80035d.hannigan1_intro.e63579"] = "Try to get our minds off this craziness for a couple of hours before it all starts again tomorrow.",
  ["80035d.hannigan1_intro.88f4a0"] = "Want to join?",
  ["80035d.hannigan1_intro.192c34"] = "<insanity>Nah, I uh. I need to go home listen to my thoughts. Decide which way the threads of fate are pulling after all this.</insanity>",
  ["80035d.hannigan1_intro.4a45a5"] = "Erm. Alright then. Have some good, uh, soul searching.",
  ["80035d.hannigan1_intro.4736e8"] = "No can do, sorry. I want to be in fresh in the morning tomorrow to get some paperwork sorted. But you try to have fun.",
  ["80035d.hannigan1_intro.2df069"] = "Sure, lead the way.",
  ["80035d.hannigan1.c985f2"] = "...psh, no way Louis XVI was a victim.",
  ["80035d.hannigan1.b4a2bd"] = "Had an uncle named Louie. There was nothin' royal about that man.",
  ["80035d.hannigan1.179110"] = "I'm just saying that he was caught between the pressures of the nobility and -",
  ["80035d.hannigan1.1c8937"] = "Nuh-uh - naw, I'm sticking to my picks!",
  ["80035d.hannigan1.ac5e01"] = "Kiss M.L.K., Marry Lionheart, Kill Louie XVI. Definitely.",
  ["80035d.hannigan1.22e2ea"] = "Well, I'm confident Richie will make you many many murderous crusader-babies.",
  ["80035d.hannigan1.5a38ad"] = "Murderous crusader-babies. Has a ring to it.",
  ["80035d.hannigan1.b7633d"] = "Boss's turn!",
  ["80035d.hannigan1.ae7830"] = "Right, let's see, hmm. Kiss, Marry, Kill: Lincoln, Ghandi and umm -",
  ["80035d.hannigan1.5ec268"] = "Thatcher!",
  ["80035d.hannigan1.bc74cd"] = "Yes! And Margaret Thatcher.",
  ["80035d.hannigan1.d9fbcf"] = "Hmm, I'll be kissing Lincoln. The man deserves a good night at the theatre.",
  ["80035d.hannigan1.21d066"] = "I think I'll be kissing Ghandi, to see him do the chastity-squirm.",
  ["80035d.hannigan1.71033f"] = "Oh, I have to kiss the Iron Lady!",
  ["80035d.hannigan1.bdebc0"] = "I'll marry Lincoln, seems like he'd be there for me.",
  ["80035d.hannigan1.2b38a5"] = "I'll marry Ghandi, expecting minimal obligations from the affair.",
  ["80035d.hannigan1.bb88fc"] = "Marry Thatcher. Definitely want to end up a baron!",
  ["80035d.hannigan1.7c196f"] = "...and unfortunately kill Lincoln. From behind, I imagine.",
  ["80035d.hannigan1.9d839f"] = "...and unfortunately kill Ghandi. Martyrdom might do wonders for his cause.",
  ["80035d.hannigan1.bba090"] = "...and unfortunately kill Thatcher. I never approved of her policies.",
  ["80035d.hannigan1.16b8bb"] = "Next round's on me!",
  ["80035d.interlude_d4.fb6568"] = "We've tracked down the people in the picture.",
  ["80035d.interlude_d4.416a3b"] = "We've brought them in. We have them in the interrogation rooms.",
  ["80035d.interlude_d4.a36671"] = "We have a sales specialist working in the building, a priest that runs the Humanitas charity and their assistant-protege.",
  ["80035d.interlude_d4.03b041"] = "The case files are ready.",
  ["80035d.interlude_e4.71f439"] = "We have a situation. Jen called.",
  ["80035d.interlude_e4.c16107"] = "She and Mordecai found Higgs.",
  ["80035d.interlude_e4.ba989e"] = "From the little they got by talking to her, they identified a very suspicious friend with her too, one Lucas Romano.",
  ["80035d.interlude_e4.6ab041"] = "He seemed extremely nervous talking to the police, and when the two suspects had a window, they bolted.",
  ["80035d.interlude_e4.775ef0"] = "There was a chase. The two of them, who seem to be armed, have holed up in an arbitrary establishment - a veterinary office.",
  ["80035d.interlude_e4.b06075"] = "<insanity>C-can't we just - just fucking gun the bastards down?! </insanity>",
  ["80035d.interlude_e4.a7b68f"] = "They have hostages. Two it seems. They are making demands.",
  ["80035d.interlude_e4.704dd1"] = "We have a line in. We'll put you on a call with them.",
  ["80035d.interlude_e4.d79766"] = "I've lined up the case files. Morty is bringing you the perp's boyfriend urgently. One Amatis Garcia.",
  ["80035d.interlude_e4.38732c"] = "If you obtain the release of hostages or one of the perps, it'll take a while, but we'll bring them right in for you to question.",
  ["80035d.interlude_e4.3b7fbc"] = "Detective, it's key that you get as much time from this Higgs as possible. You need to build a rapport with her.",
  ["80035d.interlude_d1.6d6835"] = "Jeez'. Sorry boss.",
  ["80035d.interlude_d1.826000"] = "Why are you apologizing? It's not like it's your fault, or ours.",
  ["80035d.interlude_d1.0196d6"] = "<insanity>Those Liberation Front cunts deserve to get fucking eviscerated. Slowly.</insanity>",
  ["80035d.interlude_d1.5d337a"] = "<insanity>The dead are dead, are dead deaders dead.</insanity>",
  ["80035d.interlude_d1.127763"] = "I know, I know. It's just...",
  ["80035d.interlude_d1.cd3da8"] = "... I feel like we're somehow responsible.",
  ["80035d.interlude_d1.3763e0"] = "Well, we are the department charged with stopping the people who did these very acts.",
  ["80035d.interlude_d1.58fcab"] = "So, we certainly have some responsibility - if not all of it.",
  ["80035d.interlude_d1.5e4c3e"] = "We're trying to stop murderers. That doesn't make us in any way responsible for the murders.",
  ["80035d.interlude_d1.9cb0ca"] = "We're responsible for not doing our jobs well enough. Let's do better from here on out.",
  ["80035d.interlude_d1.b01e0e"] = "That blood is on our hands. Now, let's do our very best to keep off any more.",
  ["80035d.interlude_d1.b42bc8"] = "Good evening everyone.",
  ["80035d.interlude_d1.458a66"] = "We need the room please.",
  ["80035d.interlude_d1.f7a73e"] = "I have someone here from city hall to talk to you.",
  ["80035d.interlude_d1.2e7eb9"] = "Greetings, detective. My name is Tristan Miller. I asssist mayor Patel.",
  ["80035d.interlude_d1.261c87"] = "I've been discussing things with Chief Anderson for a few hours now, but I wanted to directly address you too.",
  ["80035d.interlude_d1.55dee6"] = "These deaths, obviously... they don't look good for any of us.",
  ["80035d.interlude_d1.878488"] = "We're relying on your task force to end what is surely the greatest threat to this city: this Liberation Front.",
  ["80035d.interlude_d1.87d29e"] = "Can we count on your team to achieve this - to make the city safe again?",
  ["80035d.interlude_d1.320fb3"] = "You can. The Liberation Front will be shut down.",
  ["80035d.interlude_d1.890ac9"] = "We'll do our best, but we just don't know how deep their network runs. Can't offer any sincere guarantees.",
  ["80035d.interlude_d1.8f7b6f"] = "We may need more resources to have any chance of dealing with them.",
  ["80035d.interlude_d1.83fee2"] = "Very well. We'll supplement your next budget with some additional funds.",
  ["80035d.interlude_d1.558b29"] = "Find the bastards doing this. As soon as possible.",
  ["80035d.interlude_d1.188b7f"] = "Consider it done. I'll get my team right on it.",
  ["80035d.interlude_d1.2fd0da"] = "We'll do our very best. I just hope it's enough.",
  ["80035d.interlude_d1.85cd09"] = "The sooner you get out, the sooner we can get to work.",
  ["80035d.interlude_d3.e1553d"] = "So, we have some good news and some bad news.",
  ["80035d.interlude_d3.b71330"] = "Good news is they had elevator cameras. They're set to take pictures after each press of a button.",
  ["80035d.interlude_d3.9ea852"] = "There seems to have been a single press to go the 13th floor.",
  ["80035d.interlude_d3.bd6bf3"] = "Bad news is they weren't stored digitally, but printed. Crazy old-school security manager.",
  ["80035d.interlude_d3.971e95"] = "And the picture corresponding to the button press we're interested in was missing, of course. Foul play likely.",
  ["80035d.interlude_d3.0f59c7"] = "But! After several hours of trash-digging, pardon if I smell, I was able track down these scraps.",
  ["80035d.interlude_d3.12de06"] = "I brought them with me...",
  ["80035d.interlude_d2.1c4384"] = "We're back from looking into one of the explosions.",
  ["80035d.interlude_d2.2cf15f"] = "Office building. Triggered after hours. Still, eight dead and twenty in the hospital. No relevant witnesses off the bat.",
  ["80035d.interlude_d2.654890"] = "We've spoken to the explosive forensics, and it's like this:",
  ["80035d.interlude_d2.27058a"] = "The big boom took place on the 13th floor. A large quantity of explosive material would have been required.",
  ["80035d.interlude_d2.3d8ade"] = "That floor was closed, unpopulated. It was set to be refurbished in the coming months.",
  ["80035d.interlude_d2.cfcf8d"] = "We're going to head out again, canvas for witnesses. See if we can find any surveillance.",
  ["80035d.interlude_e2_1_tab.99c894"] = "Greetings.",
  ["80035d.interlude_e2_1_tab.24e789"] = "In light of some of the recent developments, it occured to me that there was a personal aspect best disclosed - for the record.",
  ["80035d.interlude_e2_1_tab.99113b"] = "It has to do with my background.",
  ["80035d.interlude_e2_1_tab.75e878"] = "I wanted you to know that during college I was a part of a group that subscribed to an... anti-authority political outlook.",
  ["80035d.interlude_e2_1_tab.5db0bd"] = "We did some gray hat hacktivism. Revealed some dirt on politicians.",
  ["80035d.interlude_e2_1_tab.569b2f"] = "We always made sure that the things we did were technically legal. Even if they were not necessarily moral, as I can now see, looking back.",
  ["80035d.interlude_e2_1_tab.faad9d"] = "Evidently, I hold none of those views today.",
  ["80035d.interlude_e2_1_tab.c961d0"] = "Hell, Thompson, that's not even in your file. Why would you go and tell me this?",
  ["80035d.interlude_e2_1_tab.edc173"] = "In the interest of transparency? To ensure you have all relevant information?",
  ["80035d.interlude_e2_1_tab.c4a2eb"] = "I appreciate the disclosure. You transparency on the matter is appreciated, and I will consider it past and moot.",
  ["80035d.interlude_e2_1_tab.fcf90a"] = "Thank you. It is.",
  ["80035d.interlude_e2_1_tab.fbbdae"] = "That's worrisome, Tab. Makes it hard to trust you with sensitive tasks - given our enemy.",
  ["80035d.interlude_e2_1_tab.3624b9"] = "I understand.",
  ["80035d.interlude_e2_1_tab.0ced1b"] = "Regardless, my technical skills remain at your disposal. Even if you wish me not to interact with the Liberation Front anymore.",
  ["80035d.interlude_e2_1_tab.10e5ee"] = "Did you do anything illegal as a part of this group?",
  ["80035d.interlude_e2_1_tab.dc7444"] = "No. Technically not.",
  ["80035d.interlude_e2_1_tab.0f9cdb"] = "It's in the past.",
  ["80035d.interlude_e2_1_tab.5e0b1f"] = "We'll leave it at that. Let's focus on the task at hand.",
  ["80035d.interlude_e2_1_tab.b06b76"] = "Very well.",
  ["80035d.interlude_e2_1_tab.2174e8"] = "By the way, about Cape Industries, in your declassified file?",
  ["80035d.interlude_e2_1_tab.beaec7"] = "What of it?",
  ["80035d.interlude_e2_1_tab.b655cf"] = "You're dangerous with a cause. I'm glad you're on our team and not with the Front.",
  ["80035d.interlude_e2_1_tab.b26561"] = "I didn't put the arbitrary people I happened to be born from above basic moral responsibilities. I hope that such a fact doesn't make me dangerous.",
  ["80035d.interlude_e2_1_tab.bf0e7d"] = "The sort of commitment to justice and bravery you showed there - I know I can trust you.",
  ["80035d.interlude_e2_1_tab.4bf4c6"] = "To me, to keep silent about wrongdoing is simply to be an accomplice.",
  ["80035d.interlude_e2_1_tab.c6c7e1"] = "Thank you for that trust.",
  ["80035d.interlude_e2_1_tab.909395"] = "You even turned in your own family. Do they know you squaled on them? How do I know I can trust you?",
  ["80035d.interlude_e2_1_tab.fa43b0"] = "They do not - no.",
  ["80035d.interlude_e2_1_tab.d9dbd7"] = "The family we get is an arbitrary biological incident.",
  ["80035d.interlude_e2_1_tab.030a5b"] = "Subscribing to well-considered moral values is what advances civilization. It is the only merit we can have.",
  ["80035d.interlude_e2_1_tab.faee96"] = "You should trust me for my commitment to those values.",
  ["80035d.interlude_e2_1_tab.3ec1dd"] = "If it's blind loyalty you want from your team, I can't offer that.",
  ["80035d.interlude_e2_1_tab.b68f8b"] = "Keep away from your anarchist friends at least until this operation's over, will you?",
  ["80035d.interlude_e2_1_tab.4c7cbb"] = "I do not maintain social contact with any of the friends from that era.",
  ["80035d.interlude_e2_1_tab.e51c0d"] = "But noted. I shall minimize contact with anyone that doesn't subscribe to the political mainstream.",
  ["80035d.interlude_e2_1_tab.99b461"] = "Because the lead detective said so.",
  ["80035d.interlude_g2.2a3537"] = "We've evacuated the factory.",
  ["80035d.interlude_g2.2888b1"] = "And we've determined that there could have been only one way for someone to circumvent the system and bring in any explosives.",
  ["80035d.interlude_g2.7c3669"] = "It needs to have been someone with special access to the digital security system.",
  ["80035d.interlude_g2.0da2dd"] = "The system does confirm that special access was used during this last week. This was the first time in months.",
  ["80035d.interlude_g2.40a8af"] = "And only three people have special access.",
  ["80035d.interlude_g2.e7d448"] = "The CEO and factory owner, one Aaron King.",
  ["80035d.interlude_g2.1bee0b"] = "The Chief of Security, one Steve Muradian.",
  ["80035d.interlude_g2.76e77d"] = "And the police officer that audited their security system eighteen months ago. To clear it as safe.",
  ["80035d.interlude_g2.d4d4ae"] = "...",
  ["80035d.interlude_g2.3d1335"] = "One Tab Thompson.",
  ["80035d.interlude_g2.d5d612"] = "I hope you understand. Tab has to be a part of this questioning.",
  ["80035d.interlude_g2.e71130"] = "That's bullshit. You know full well Tab can't have anything to do with this!",
  ["80035d.interlude_g2.9cb309"] = "Well, I need you to include Thompson in this questioning - as a real subject. Imagine how it would look, otherwise.",
  ["80035d.interlude_g2.d0f15e"] = "Not to mention how this Liberation Front has a shockingly wide spectrum of members.",
  ["80035d.interlude_g2.23b528"] = "I understand. We can't look like we're giving our own a pass.",
  ["80035d.interlude_g2.8d0960"] = "Exactly. Not to mention how this Liberation Front has a shockingly wide spectrum of members.",
  ["80035d.interlude_g2.a78076"] = "Absolutely. I'll be sure to grill Tab as seriously as the rest. We can't be totally sure they're not involved.",
  ["80035d.interlude_g2.b06b76"] = "Very well.",
  ["80035d.interlude_g2.ea96f9"] = "Get in there and get a location for those explosives, before they blow up the factory.",
  ["80035d.interlude_g2.9de214"] = "Meanwhile, we'll try to get this Benno Weiss who is hiding with his uncle out of state.",
  ["80035d.interlude_g1.96aa7f"] = "These fuckers are ready for another attack. We need to treat this as cold, hard fact.",
  ["80035d.interlude_g1.3aaada"] = "<insanity>Bastards! Motherfuckers! Fucking, ggghhm... fucking cunt goblins!</insanity>",
  ["80035d.interlude_g1.f89b63"] = "<insanity>They shan't best me! I shall foil these evildoers!</insanity>",
  ["80035d.interlude_g1.951bf8"] = "Uh... wha -",
  ["80035d.interlude_g1.8796a3"] = "Get to it - now! Identify where this factory is exactly. Evacuate the place urgently.",
  ["80035d.interlude_g1.64fd6b"] = "Go! Go! Go!",
  ["80035d.jigsaw_conclusion.fe0368"] = "This is who we are looking for. Find them. Bring them to me.",
  ["80035d.interlude_f1.c6ce12"] = "Things are finally looking up.",
  ["80035d.interlude_f1.8446a8"] = "Between Ennis, Wilson's testimony, Adams, the details from Novak, and now Higgs and Romano, we've gathered lots of insights and are finally getting the critical mass to tie more of the leads together.",
  ["80035d.interlude_f1.877eef"] = "We're going to get cracking on proving the cases as many of these suspects are beginning to look like clear-cut Liberation Front members.",
  ["80035d.interlude_f2.07dc05"] = "We've narrowed down a list of four perps that are virtually certain LF members. The evidence is overwhelming.",
  ["80035d.interlude_f2.345881"] = "Benno Weiss. Then, Anton Drasko. Lynda Bailey. And Helene Koufos. Each one of the last three is linked to one of the attempted bombings.",
  ["80035d.interlude_f2.d42204"] = "The prosecutors agreed. We can book them on the face-value of the evidence alone. So, get ready to question.",
  ["80035d.interlude_f3.fa40f6"] = "Only Benno Weiss they couldn't get - yet. We're sure he's in hiding with his uncle - out of state - so it might be a while.",
  ["80035d.interlude_f3.747a22"] = "But the other three are in. Full-time mom Linda Bailey seemed to have handled our security guard Wilson.",
  ["80035d.interlude_f3.e031ce"] = "Anton Drasko, porn producer, seemed to have provided the explosives for Father Gabriel.",
  ["80035d.interlude_f3.b8a0b4"] = "And Helene Koufos, a yoga instructor, was in very close contact with our hostage-taker Cassandra Higgs.",
  ["80035d.interlude_f3.6bbe46"] = "Helene is deaf-mute, so we brought in an interpreter for you.",
  ["80035d.interlude_f3.30941d"] = "Tab's prepped you the case files on them.",
  ["80035d.interlude_f3.14a6fb"] = "They're all set to go in the interrogation rooms.",
  ["80035d.interlude_f3.e385c5"] = "Crazy thing is, they didn't even fight it. They've already confessed to being with the Front. All three.",
  ["80035d.interlude_f3.543249"] = "So, the stakes here are whether you can extract from them the next move The Liberation Front will make.",
  ["80035d.interlude_f3.023e1d"] = "Go get'm!",
  ["81039c.interview3.02876a"] = "We've brought in another reporter for you to talk to.",
  ["81039c.interview3.437347"] = "Miss Becker handled the technicalities in the last interview.",
  ["81039c.interview3.5f22bf"] = "This time, Miss Lisa Nguyen-Holst is looking to write more of a human interest story.",
  ["81039c.interview3.a8f461"] = "I want to learn all about the team that caught the Twin Bombers!",
  ["81039c.interview3.16afbd"] = "Shall we?",
  ["81039c.interview3.ae9403"] = "Fuck off out of here. Both of you. Get out of my office...",
  ["81039c.interview3.2d5178"] = "I'm sorry. We're getting too close to the leadership of the Liberation Front for me to be spending time doing interviews.",
  ["81039c.interview3.a609e6"] = "Very well. Let's sit down, Miss Nguyen-Holst.",
  ["81039c.interlude_i1.800b1c"] = "We're getting so close, boss!",
  ["81039c.interlude_i1.6784f5"] = "Corroborating everything, the mounting evidence, pushing all the Liberation Front members we've caught, outside sources...",
  ["81039c.interlude_i1.80fea2"] = "We finally have something solid. One Alexa Brown, connected to travel arrangements apparently made for the Front's top leadership.",
  ["81039c.interlude_i1.25fd2c"] = "We have something solid. One Alexa Brown, connected to travel arrangements apparently made for the Liberation Front actual top leadership.",
  ["81039c.interlude_i1.bb3809"] = "Rumor on the street is that the Front is looking outside the city and country, gathering other radicals for the cause.",
  ["81039c.interlude_i1.07eb32"] = "Trying to bring together under their umbrella all the psychos ready to kill for ideology.",
  ["81039c.interlude_i1.f40677"] = "We're heading out, to grab Brown.",
  ["81039c.hannigan3_intro.120eb8"] = "Boss! We're headed to Hannigan's. Comin'?",
  ["81039c.hannigan3_intro.2d7ed4"] = "No can do, sorry. I'm supposed to go to this charity dinner thing. Have fun.",
  ["81039c.hannigan3_intro.cafc00"] = "Sure, go on ahead and I'll catch up with you there!",
  ["81039c.hannigan3.32cd22"] = "I have one for you, fearless leader!",
  ["81039c.hannigan3.badbad"] = "Kiss, Marry, Kill - one of these younger members of your team.",
  ["81039c.hannigan3.6475d0"] = "If this doesn't offend anyone, that is.",
  ["81039c.hannigan3.a97cea"] = "Heh, it's fine.",
  ["81039c.hannigan3.539ab4"] = "Jen, Morty and Tab.",
  ["81039c.hannigan3.792760"] = "...totally. Kiss Tab, Marry Jen, Kill the boss.",
  ["81039c.hannigan3.655347"] = "Sorry boss, heh.",
  ["81039c.hannigan3.882800"] = "Well, I am not babysitting any resulting kids, I can tell you that.",
  ["81039c.hannigan3.b46b7d"] = "Boss's turn! Three of us. Kiss, Marry, Kill.",
  ["81039c.hannigan3.bbe5a4"] = "We promise not to take it personally.",
  ["81039c.hannigan3.49562e"] = "Hmm, I'll be kissing Jen, can't say no to that warmth.",
  ["81039c.hannigan3.f67cf7"] = "I have to kiss Tab, I suspect much technique can be learned in the process.",
  ["81039c.hannigan3.608d98"] = "Kissing Mordecai, seems like he'd hold me with respectful safety.",
  ["81039c.hannigan3.9c5514"] = "I'll marry Jen, seems like she could educate the heck out of kids.",
  ["81039c.hannigan3.f57b29"] = "I'll marry Tab, get some order into my life!",
  ["81039c.hannigan3.e4fbce"] = "Marry Morty, nice trophy husband.",
  ["81039c.hannigan3.c808f7"] = "...and unfortunately kill Jen, but only after we have taken out the Front!",
  ["81039c.hannigan3.324575"] = "...and unfortunately kill Tab, but only after we have taken out the Front!",
  ["81039c.hannigan3.0832f5"] = "...and unfortunately kill Morty, but only after we have taken out the Front!",
  ["81039c.hannigan3.be5bd9"] = "Fun. Say Jen, have you told Joseph the story with you and the duck, in college?",
  ["81039c.hannigan3.3d922c"] = "Fun. Say Jen, have you told the boss the story with you and the duck, in college?",
  ["81039c.hannigan3.991553"] = "Heh, no. So, it goes like this. Second year of college, in my dorm-",
  ["81039c.interlude_i2.48e679"] = "We, uh...",
  ["81039c.interlude_i2.f3023a"] = "We found Brown deceased in her appartment.",
  ["81039c.interlude_i2.c8ebd6"] = "We found Miss Brown deceased in her appartment.",
  ["81039c.interlude_i2.201ac6"] = "<insanity>You live by Front's sword, you die by the Front's sword.</insanity>",
  ["81039c.interlude_i2.5d641b"] = "<insanity>Don't even report it. Let that terrorist rot in her apartment.</insanity>",
  ["81039c.interlude_i2.4f6863"] = "Apparent suicide. Though we can't exclude that the Liberation Front is tying up vulnerable loose ends.",
  ["81039c.interlude_i2.74f0ea"] = "Plenty of LF material around her apartment, but just the usual propaganda, no names.",
  ["81039c.interlude_i2.866dc4"] = "This woman was our route to the leadership. The best one yet.",
  ["81039c.interlude_i2.b6e231"] = "This chick supposedly handled the leadership's travels. It sucks that we now have nothing.",
  ["81039c.interlude_i2.071ecd"] = "Excuse me.",
  ["81039c.interlude_i2.3ce61b"] = "Got these out of a paper shredder. Maybe you can make something out of it.",
  ["81039c.interlude_i3.c42f56"] = "Morty called. The flight the four were on is about to take off.",
  ["81039c.interlude_i3.9ef858"] = "He doesn't technically have a warrant, and it seems the air marshals won't let him take all of four of them.",
  ["81039c.interlude_i3.2821d8"] = "They'll only give him two. Say he can handle escorting them himself.",
  ["81039c.interlude_i3.6cac22"] = "It's a procedurally stupid situation, but Morty will need a decision. Now.",
  ["81039c.interlude_i3.b71371"] = "You'll have to tell him the two persons you want brought in from the four suspects.",
  ["81039c.interlude_i3.bfba56"] = "I'm afraid, I have more bad news on top of that.",
  ["81039c.interlude_i3.3dd50c"] = "Abraham Jamail just called. The top hotshot criminal lawyer, \"Honest Abe\" from the TV commercials.",
  ["81039c.interlude_i3.e48ec2"] = "It turns out he's been hired by anonymous parties to represent all of the four suspects on the plane.",
  ["81039c.interlude_i3.d9067a"] = "The moment he's here, you can consider the interrogation over. All we have is circumstantial.",
  ["81039c.interlude_i3.bb53f6"] = "He's fortunately coming in from outside of town, so Morty should be able to bring in your chosen two a bit earlier than his arrival.",
  ["81039c.interlude_i3.7e9bfb"] = "You simply must draw from them some sort of confirmation of who might be Liberation Front leadership before he arrives!",
  ["81039c.interlude_i3.bae062"] = "You need to get some sort of confirmation of who might be Liberation Front leadership before he arrives.",
  ["81039c.interlude_h3.31ae94"] = "How was it?!",
  ["81039c.interlude_h3.537a99"] = "Hall is a hard guy, but I respect his drive. We seem to be in the clear.",
  ["81039c.interlude_h3.4aaa10"] = "Hall is a damned psychopath. I can't believe how he acted in there. We seem to be cleared though - for now.",
  ["81039c.interlude_h3.409cf1"] = "Don't know what the hell that was in there, but it doesn't matter. We need to get back to work.",
  ["81039c.interlude_h3.376878"] = "Back to it, everyone.",
  ["81039c.interlude_h2.d4f3b1"] = "Detective, this is Elias Hall, Internal Affairs.",
  ["81039c.interlude_h2.99c894"] = "Greetings.",
  ["81039c.interlude_h2.724b9e"] = "If you're both ready, head in for questioning.",
  ["81039c.interlude_h2.2f6cb1"] = "I have my case file ready. We can go ahead.",
  ["81039c.interlude_h2.454874"] = "I look forward to hearing your conclusions after you're done, Mr. Hall.",
  ["81039c.interlude_h2.aae2cd"] = "I'm sure you are, Chief Anderson. I'm sure you are.",
  ["81039c.interlude_h1.891f5e"] = "I've been protecting you, because you're clearly getting results.",
  ["81039c.interlude_h1.6be1f2"] = "But push has come to shove. There's an internal investigation running against you.",
  ["81039c.interlude_h1.f0443a"] = "They're currently reviewing documents, taking testimonies.",
  ["81039c.interlude_h1.eff99b"] = "<insanity>This cur dares to question my honor?!</insanity>",
  ["81039c.interlude_h1.e81d39"] = "<insanity>Psh, ain't no thang, Chief. I'm un-fuckin'-touchable. Nuh-uh. Comin' after me, is he?</insanity>",
  ["81039c.interlude_h1.3fbc0a"] = "Erm... Yes?",
  ["81039c.interlude_h1.8617e9"] = "Be ready to be interrogated before this internal investigation's conclusion.",
  ["81039c.interlude_h1.153dcc"] = "The IA asshole running it seems dead set on burying you, so be careful.",
  ["81039c.interlude_j.5f01b5"] = "Well, well, Detective. You've had quite the field day with my clients in my absence, haven't you?",
  ["81039c.interlude_j.00aa36"] = "Only what they chose to tell me, councillor.",
  ["81039c.interlude_j.df01d7"] = "Well, with them being sooo innocent, I'm sure it hasn't been a problem.",
  ["81039c.interlude_j.935a23"] = "How exactly do you sleep at night? Representing terrorists?",
  ["81039c.interlude_j.8cb639"] = "Detective...",
  ["81039c.interlude_j.07e0ce"] = "Well, that's quite, as the Brits say, 'cheeky' - now isn't it?",
  ["81039c.interlude_j.db0a07"] = "Alas, despite their dismal treatment, I've been talking to Mr. Miller and Chief Anderson here.",
  ["81039c.interlude_j.74a47d"] = "And because all three of my clients are of completely good intent, the good gentlemen and I have reached an agreement.",
  ["81039c.interlude_j.22ab97"] = "We will not press charges against the abusive police practices thus far.",
  ["81039c.interlude_j.6b4efc"] = "And they will even willingly discuss with you, Detective.",
  ["81039c.interlude_j.b198af"] = "Recorder stays on throughout, or else they leave.",
  ["81039c.interlude_j.bde845"] = "However, all of this under the condition that nothing of what one says can used in their own incrimination. Yes?",
  ["81039c.interlude_j.3030dc"] = "Mhm.",
  ["81039c.interlude_j.612ab4"] = "We've signed documents to that effect, yes.",
  ["81039c.interlude_j.3322d9"] = "Wonderful! Then let's get this over with.",
  ["81039c.interlude_j.0c12f6"] = "Don't take long. They're important people. They have places to be.",
  ["81039c.interlude_j.24376e"] = "I can't believe you fools signed something like that.",
  ["81039c.interlude_j.4a9f45"] = "I see what you did there, Chief. I can work with this.",
  ["81039c.interlude_j.f9cc84"] = "Are you fucking Liberation front?! Why would you sign something like that?",
  ["81039c.interlude_j.65026d"] = "I should kick you out, you arrogant shit!",
  ["81039c.interlude_j.2e85a6"] = "We had to sign, given the context, but it's an opportunity.",
  ["81039c.interlude_j.1b937f"] = "Indeed. The wording allows for a window. They can't self-incriminate...",
  ["81039c.interlude_j.5ef606"] = "... but nothing prevents them from incriminating one another.",
  ["81039c.interlude_j.35142b"] = "You need to turn them against each other. Go get'm.",
  ["81039c.interlude_j.d5d6f2"] = "This is for all the marbles. Take down the Liberation Front!",
  ["81039c.interlude_h1_1_mordecai.351fb2"] = "Hey, boss? Before you head home-",
  ["81039c.interlude_h1_1_mordecai.19799c"] = "Wanted to talk to you out here, away from the others.",
  ["81039c.interlude_h1_1_mordecai.5cefaa"] = "Heard about the Internal Affairs investigation thing you need to deal with tomorrow.",
  ["81039c.interlude_h1_1_mordecai.8671ef"] = "I know this Hall guy, seen him operate before. Rumor is that he's a tough cookie.",
  ["81039c.interlude_h1_1_mordecai.e9d54f"] = "And, look, I just want to know...",
  ["81039c.interlude_h1_1_mordecai.ac2c2d"] = "Is there actually any dirt on you? Cut any corners? Did any nasties?",
  ["81039c.interlude_h1_1_mordecai.6c8d57"] = "Just give it to me straight.",
  ["81039c.interlude_h1_1_mordecai.b897c0"] = "I've really been doing my best to be by the book, Morty. It's all clean.",
  ["81039c.interlude_h1_1_mordecai.4e3e0d"] = "Okay. I'm with you then.",
  ["81039c.interlude_h1_1_mordecai.5df7bc"] = "Results come first, stopping these psychos. That's meant cutting some corners - ethically speaking.",
  ["81039c.interlude_h1_1_mordecai.48e90c"] = "Erm, if you say so... yea.",
  ["81039c.interlude_h1_1_mordecai.7cd8a6"] = "I've done some bad things, Morty. But they're on me. No need for you to take on any of that load.",
  ["81039c.interlude_h1_1_mordecai.e5802d"] = "I appreciate what you're tryin' to do here, to protect us.",
  ["81039c.interlude_h1_1_mordecai.adca0d"] = "But you don't have to. We're here for ya'.",
  ["81039c.interlude_h1_1_mordecai.ed583f"] = "Hall being here means there's smoke. How big's the fire?",
  ["81039c.interlude_h1_1_mordecai.c66b79"] = "If you say so.",
  ["81039c.interlude_h1_1_mordecai.c23da6"] = "I appreciate you bein' on the level with me on this, at least.",
  ["81039c.interlude_h1_1_mordecai.2af90d"] = "Look, I know whatever you've done. It was for the cause.",
  ["81039c.interlude_h1_1_mordecai.28f8dc"] = "Right or wrong, you tried your best.",
  ["81039c.interlude_h1_1_mordecai.68aae5"] = "Thanks for checking in, Morty. I have this.",
  ["81039c.interlude_h1_1_mordecai.c26fad"] = "G'luck with Hall, boss. G'night.",
  ["81039c.interlude_h1_1_mordecai.a61fad"] = "I know from your declassified file about how you had some dirt on yourself too, from the distant past...",
  ["81039c.interlude_h1_1_mordecai.165b32"] = "Huh. The armed robbery thing.",
  ["81039c.interlude_h1_1_mordecai.407c56"] = "... and I never needed to confront you about it.",
  ["81039c.interlude_h1_1_mordecai.cc74cc"] = "Huh. Point taken. I'll fuck off about the IA stuff.",
  ["81039c.interlude_h1_1_mordecai.d31c20"] = "... and how you snitched on your mates to get a clean record.",
  ["81039c.interlude_h1_1_mordecai.45c7b7"] = "Yea, well...",
  ["81039c.interlude_h1_1_mordecai.ed691b"] = "That was bullshit of me to do, but there's not much I can do about it now.",
  ["81039c.interlude_h1_1_mordecai.573672"] = "... and how you still became a great cop after all of that.",
  ["81039c.interlude_h1_1_mordecai.81dfc9"] = "Heh, thanks, but...",
  ["81039c.interlude_h1_1_mordecai.d83c70"] = "Hell, I proved zero loyalty to those guys.",
  ["81039c.interlude_h1_1_mordecai.c5e988"] = "Those guys, who were just as guilty as I was.",
  ["81039c.interlude_h1_1_mordecai.835750"] = "One of them ended up super bad. A total meth-head.",
  ["81039c.interlude_h1_1_mordecai.9d40d0"] = "So, nah, being a good cop or not today, what I did was just betrayal.",
  ["81039c.interlude_h1_1_mordecai.4776f8"] = "Anyway, good luck with Hall. G'night.",
  ["81039c.interlude_h1_1_mordecai.c9ed37"] = "This Hall business is mine to deal with. Don't worry about it. Focus on your own work.",
  ["81039c.interlude_h1_1_mordecai.e68d24"] = "Right. G'night.",
  ["81039c.interlude_h3_1_joseph.6c8c27"] = "It's time to talk.",
  ["81039c.interlude_h3_1_joseph.b9e157"] = "You're coming up on the leadership, nearing the end-game.",
  ["81039c.interlude_h3_1_joseph.ee7ad1"] = "You're not going to get a lot of attempts at cracking them.",
  ["81039c.interlude_h3_1_joseph.c8ecd3"] = "Chances are, whoever's leading this, that they're powerful people.",
  ["81039c.interlude_h3_1_joseph.d36ce8"] = "The Burgundy Riots were supposedly a student movement.",
  ["81039c.interlude_h3_1_joseph.aad13b"] = "Bullshit.",
  ["81039c.interlude_h3_1_joseph.124e37"] = "Ringleaders using impressionable youth for their own ends.",
  ["81039c.interlude_h3_1_joseph.3ad830"] = "So, if you do get them, you have to be ready to act...",
  ["81039c.interlude_h3_1_joseph.56c723"] = "...decisively, during the very small window of time that you'll have them.",
  ["81039c.interlude_h3_1_joseph.cfa9a4"] = "Do you mean... acting extrajudicially?",
  ["81039c.interlude_h3_1_joseph.4c1069"] = "Well, yes.",
  ["81039c.interlude_h3_1_joseph.5ff73e"] = "Technically, yes. If you allow them play the system, they will do it.",
  ["81039c.interlude_h3_1_joseph.659861"] = "They can do so much damage - even from inside a cell.",
  ["81039c.interlude_h3_1_joseph.5cd5fd"] = "Not that you'll ever get them in jail.",
  ["81039c.interlude_h3_1_joseph.133650"] = "They will either win their trial, or end up off the map.",
  ["81039c.interlude_h3_1_joseph.5927b0"] = "So, if it happens that after you get conclusive proof on them, they perish...",
  ["81039c.interlude_h3_1_joseph.026f39"] = "... considered it mission accomplished.",
  ["81039c.interlude_h3_1_joseph.76b351"] = "What would you recommend I do?",
  ["81039c.interlude_h3_1_joseph.4019ae"] = "They can do so much damage even from inside a cell.",
  ["81039c.interlude_h3_1_joseph.7a97d2"] = "They either win their trial, or end up off the map.",
  ["81039c.interlude_h3_1_joseph.84cef0"] = "What did you do to end the Burgundy Riots?",
  ["81039c.interlude_h3_1_joseph.097b97"] = "I had the evidence I needed to prove them guilty.",
  ["81039c.interlude_h3_1_joseph.ae034a"] = "And looked the other way as an escape attempt was foiled.... with the use of lethal force.",
  ["81039c.interlude_h3_1_joseph.3afaa8"] = "Because you have to understand.",
  ["81039c.interlude_h3_1_joseph.8aed06"] = "Erm... no, no.",
  ["81039c.interlude_h3_1_joseph.2f004d"] = "But if it happens that they resist arrest, or attempt escape...",
  ["81039c.interlude_h3_1_joseph.dec1f8"] = "Well, a response using lethal force would fix a lot of problems.",
  ["81039c.interlude_h3_1_joseph.94c334"] = "But if it happens that they resist arrest or attempt to escape...",
  ["81039c.interlude_h3_1_joseph.378bd6"] = "What did you do, to end the Burgundy Riots?",
  ["81039c.interlude_h3_1_joseph.c0b474"] = "The leader we captured attempted to escape.",
  ["81039c.interlude_h3_1_joseph.101e94"] = "He died during that attempt.",
  ["81039c.interlude_h3_1_joseph.d9f375"] = "And that was the real end to things.",
  ["81039c.interlude_h3_1_joseph.2844bb"] = "Until the Liberation Front showed up, anyway.",
  ["81039c.interlude_h3_1_joseph.a137d5"] = "So, a sudden end can be a good end...",
  ["81039c.interlude_h3_1_joseph.56cf2d"] = "I appreciate your directness and council, Joseph, even if I'm not sure that I agree.",
  ["81039c.interlude_h3_1_joseph.75553b"] = "Keep it in mind.",
  ["81039c.interlude_h3_1_joseph.8afbd3"] = "You're right. Once I have them proven as guilty, I need to see them ended - whatever the personal cost.",
  ["81039c.interlude_h3_1_joseph.091fb0"] = "Go get'm, officer.",
  ["81039c.interlude_h3_1_joseph.70292b"] = "This is an outrageous proposition! How are you not worried about me reporting you after all this?!",
  ["81039c.interlude_h3_1_joseph.e5209e"] = "At my age? What could happen to me?",
  ["81039c.interlude_h3_1_joseph.3a351e"] = "Getting fired? Disgraced? Jailed?",
  ["81039c.interlude_h3_1_joseph.58e5f6"] = "I don't care.",
  ["81039c.interlude_h3_1_joseph.cb0cc6"] = "But I do care that this new Riot, this Front, is ended.",
  ["81039c.interlude_h3_1_joseph.b6d64e"] = "And you should be focusing on that too.",
  ["81039c.jigsaw_conclusion2.732923"] = "This is who we're looking for. Head to that plane now and bring them to me!",
  ["81039c.interlude_g3.2725df"] = "Good job in there.",
  ["81039c.interlude_g3.fb7a06"] = "Before you get to the press release for this one, though...",
  ["81039c.interlude_g3.483749"] = "The factory's covered by national security confidentiality rules.",
  ["81039c.interlude_g3.bb3991"] = "Word the press release in such a way that keeps obscured how dangerous things actually got...",
  ["efd00d.example.24de61"] = "Hi, Tab!",
  ["efd00d.example.e4f7e3"] = "Hi, Jen!",
  ["efd00d.example.36a09a"] = "So, how's work?",
  ["efd00d.example.7ebcbb"] = "The usual...",
  ["efd00d.example.f99ed4"] = "Great!",
  ["efd00d.example.122d3d"] = "Say, what color would you pick for this dossier's color coding?",
  ["efd00d.example.2d0114"] = "Yellow",
  ["efd00d.example.6e1ba3"] = "Nice choice! I like Yellow",
  ["efd00d.example.c61091"] = "Red",
  ["efd00d.example.059804"] = "I love red! It's great!",
}
